import type { TransitionProps } from 'react-transition-group/Transition';

function updateNodeStyle(node: HTMLElement, height: string, opacity: string) {
  node.style.height = height;
  node.style.opacity = opacity;
}

function resetNodeStyle(node: HTMLElement) {
  node.style.removeProperty('height');
  node.style.removeProperty('opacity');
  node.style.removeProperty('overflow');
}

export const collapseTransitionProps: TransitionProps = {
  onEnter: (node: HTMLElement) => {
    updateNodeStyle(node, '0', '0');
  },
  onEntering: (node: HTMLElement) => {
    updateNodeStyle(node, `${node.scrollHeight}px`, '1');
  },
  onEntered: (node: HTMLElement) => {
    resetNodeStyle(node);
  },
  onExit: (node: HTMLElement) => {
    updateNodeStyle(node, `${node.offsetHeight}px`, '1');
  },
  onExiting: (node: HTMLElement) => {
    updateNodeStyle(node, '0', '0');
  },
  onExited: (node: HTMLElement) => {
    resetNodeStyle(node);
  },
  timeout: 200,
};
